  <HEADER encrypted="1" encrypted_ver="1" build="0.0704.1001.0000.13.0" user="elv23" computer="DESKTOP-JDIAKSC" date="2025.08.10 22'34'57" map_xs="128" map_ys="128" north_angle="0" extra_map_edge="1" tileset="volcanic" environment="Default Environment" players="8" name="Битва мастер юнитов" id="bitva_master_unitov" style="0" description="Задействованы специальные правила: каждый игрок начинает с мастер-юнитом его нации. С его помощью необходимо захватить свой первый город и начать обыденное развитие. Много битв повидала эта земля, но со временем, армии покинули ее, сочтя малоперспективной. Теперь здесь хозяйничают местные твари и существа из пустыни Калахезе. Они же, наряду с оставшимися немногочисленными диггерами, и охраняют последние ресурсы." enable_dominance="1" preview_image_ext="tga" version="12" allowable_game_styles="4294967295" default_game_style="-1" victory="255" elimination="1" allies="10" living_world_bird="22" force_rush_rules_disable="0" does_override_teamstyle="0" teamstyle_override_value="0" starts_required="0" starts_no_pick="0" show_all_villages="0" generate_script="0" num_villages="8" num_special="1" num_villages_override="32" num_special_override="15">
